import { useEffect, useMemo, useState } from "react";
import AnalyzePage from "./views/AnalyzePage";
import { Menu, X, Sparkles } from "lucide-react";
import "./index.css";

const NAV_ITEMS = [
  { label: "Features", id: "features" },
  { label: "How it Works", id: "how-it-works" },
  { label: "Pricing", id: "pricing" },
] as const;

export default function App() {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  // Stable year string (avoid re-render mismatch if you ever SSR later)
  const year = useMemo(() => new Date().getFullYear(), []);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 768) setMobileMenuOpen(false);
    };
    window.addEventListener("resize", handleResize, { passive: true });
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    // Prevent body scroll when mobile menu is open
    document.body.style.overflow = mobileMenuOpen ? "hidden" : "";
    return () => {
      document.body.style.overflow = "";
    };
  }, [mobileMenuOpen]);

  function scrollToTop() {
    setMobileMenuOpen(false);
    window.scrollTo({ top: 0, behavior: "smooth" });
  }

  function scrollToSection(id: string) {
    setMobileMenuOpen(false);
    const el = document.getElementById(id);
    if (!el) return;
    const y = el.getBoundingClientRect().top + window.scrollY - 96; // offset for sticky nav
    window.scrollTo({ top: y, behavior: "smooth" });
  }

  return (
    <div className="min-h-screen bg-slate-50 relative selection:bg-indigo-500/30 selection:text-indigo-900 overflow-x-hidden font-sans">
      {/* Enhanced Dynamic Background */}
      <div className="fixed inset-0 -z-10 h-full w-full bg-slate-50 no-print overflow-hidden">
        {/* Base Gradient */}
        <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-indigo-50/40 via-white to-purple-50/40" />

        {/* Animated Blobs */}
        <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-purple-200/40 rounded-full mix-blend-multiply filter blur-[80px] opacity-70 animate-blob" />
        <div className="absolute top-[10%] right-[-10%] w-[500px] h-[500px] bg-indigo-200/40 rounded-full mix-blend-multiply filter blur-[80px] opacity-70 animate-blob animation-delay-2000" />
        <div className="absolute -bottom-[10%] left-[20%] w-[500px] h-[500px] bg-pink-200/40 rounded-full mix-blend-multiply filter blur-[80px] opacity-70 animate-blob animation-delay-4000" />

        {/* Noise Texture */}
        <div
          className="absolute inset-0 opacity-[0.035] pointer-events-none z-[1]"
          style={{
            backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.7' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")`,
          }}
        />

        {/* Grid Pattern */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#8080800a_1px,transparent_1px),linear-gradient(to_bottom,#8080800a_1px,transparent_1px)] bg-[size:24px_24px] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_0%,#000_70%,transparent_100%)] z-[2]" />
      </div>

      {/* Sticky Navigation */}
      <nav
        className={`fixed top-0 left-0 right-0 z-[100] transition-all duration-300 no-print ${
          scrolled || mobileMenuOpen
            ? "bg-white/80 backdrop-blur-xl border-b border-slate-200/50 shadow-sm py-3"
            : "bg-transparent border-b border-transparent py-5"
        }`}
        aria-label="Primary"
      >
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center">
            {/* Logo */}
            <button
              type="button"
              className="flex items-center gap-2.5 group cursor-pointer select-none"
              onClick={scrollToTop}
              aria-label="Scroll to top"
            >
              <div className="relative flex items-center justify-center w-10 h-10 rounded-xl bg-gradient-to-tr from-indigo-600 to-violet-600 shadow-lg shadow-indigo-500/20 group-hover:shadow-indigo-500/40 group-hover:scale-105 transition-all duration-300">
                <Sparkles className="w-5 h-5 text-white" />
              </div>
              <span className="font-bold text-xl tracking-tight text-slate-900 group-hover:text-indigo-600 transition-colors">
                AI<span className="text-indigo-600">Visibility</span>
              </span>
            </button>

            {/* Desktop Nav */}
            <div className="hidden md:flex items-center space-x-1">
              {NAV_ITEMS.map((item) => (
                <button
                  key={item.id}
                  type="button"
                  onClick={() => scrollToSection(item.id)}
                  className="text-sm font-medium text-slate-600 hover:text-indigo-600 hover:bg-white/50 px-4 py-2 rounded-full transition-all"
                >
                  {item.label}
                </button>
              ))}
            </div>

            {/* Desktop CTA */}
            <div className="hidden md:flex items-center gap-3">
              <button
                type="button"
                className="text-sm font-semibold text-slate-600 hover:text-indigo-600 transition-colors px-4 py-2"
                onClick={() => {
                  setMobileMenuOpen(false);
                  window.location.assign("/auth");
                }}
              >
                Sign in
              </button>
              <button
                type="button"
                className="bg-slate-900 text-white px-5 py-2.5 rounded-full text-sm font-semibold hover:bg-indigo-600 hover:shadow-lg hover:shadow-indigo-500/25 transition-all transform hover:-translate-y-0.5 active:translate-y-0"
                onClick={() => {
                  setMobileMenuOpen(false);
                  window.location.assign("/auth?mode=signup");
                }}
              >
                Get Started
              </button>
            </div>

            {/* Mobile Menu Button */}
            <div className="md:hidden">
              <button
                type="button"
                onClick={() => setMobileMenuOpen((v) => !v)}
                className="p-2 rounded-lg text-slate-600 hover:bg-slate-100/50 transition-colors"
                aria-label="Toggle menu"
                aria-expanded={mobileMenuOpen}
              >
                {mobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu Dropdown */}
        {mobileMenuOpen && (
          <div className="md:hidden border-t border-slate-100 bg-white/95 backdrop-blur-xl absolute w-full left-0 animate-in slide-in-from-top-5 z-[90] shadow-xl">
            <div className="px-4 pt-4 pb-6 space-y-3">
              {NAV_ITEMS.map((item) => (
                <button
                  key={item.id}
                  type="button"
                  onClick={() => scrollToSection(item.id)}
                  className="block w-full text-left px-4 py-3 rounded-xl text-base font-medium text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 transition-colors"
                >
                  {item.label}
                </button>
              ))}

              <div className="h-px bg-slate-100 my-2" />

              <div className="grid grid-cols-2 gap-4">
                <button
                  type="button"
                  className="w-full px-4 py-3 rounded-xl text-slate-600 font-semibold border border-slate-200 hover:bg-slate-50 transition-colors"
                  onClick={() => {
                    setMobileMenuOpen(false);
                    window.location.assign("/auth");
                  }}
                >
                  Sign in
                </button>
                <button
                  type="button"
                  className="w-full px-4 py-3 rounded-xl bg-indigo-600 text-white font-semibold hover:bg-indigo-700 shadow-md transition-colors"
                  onClick={() => {
                    setMobileMenuOpen(false);
                    window.location.assign("/auth?mode=signup");
                  }}
                >
                  Get Started
                </button>
              </div>
            </div>
          </div>
        )}
      </nav>

      {/* Main Content Padding for Fixed Header */}
      <main className="relative z-10 pt-28 md:pt-36 pb-20">
        {/* Give your AnalyzePage anchors it can render against */}
        <section id="top">
          <AnalyzePage />
        </section>
      </main>

      <footer className="border-t border-slate-200/60 bg-white/50 backdrop-blur-sm no-print relative z-10">
        <div className="max-w-7xl mx-auto px-4 py-12 md:py-16">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <button type="button" className="flex items-center gap-2" onClick={scrollToTop} aria-label="Home">
              <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center shadow-md shadow-indigo-500/20">
                <Sparkles className="w-4 h-4 text-white" />
              </div>
              <span className="font-bold text-lg text-slate-900">AIVisibility</span>
            </button>
            <p className="text-slate-500 text-sm font-medium">
              &copy; {year} AI Visibility Engine. All rights reserved.
            </p>
          </div>
        </div>
      </footer>

    
    </div>
  );
}
